// ═══════════════════════════════════════════
// VALIDATION DES DONNÉES DU FORMULAIRE
// ═══════════════════════════════════════════

const input = $input.first().json.body || $input.first().json;

const prenom = (input.prenom || '').trim();
const email = (input.email || '').trim().toLowerCase();
const nom_commerce = (input.nom_commerce || '').trim();
const ville = (input.ville || '').trim();
const nb_avis = parseInt(input.nb_avis) || 0;
const lien_google = (input.lien_google || '').trim();

// Validation email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const isEmailValid = emailRegex.test(email);

// Validation champs obligatoires
const errors = [];
if (!prenom) errors.push('Prénom manquant');
if (!email) errors.push('Email manquant');
else if (!isEmailValid) errors.push('Email invalide');
if (!nom_commerce) errors.push('Nom du commerce manquant');
if (!ville) errors.push('Ville manquante');

// Détermination du segment
let segment;
if (nb_avis <= 5) segment = '0-5';
else if (nb_avis <= 20) segment = '6-20';
else segment = '21+';

// Détection si lien Google fourni
const hasGoogleLink = lien_google.includes('google.com/maps') || 
                      lien_google.includes('goo.gl') ||
                      lien_google.includes('maps.app.goo.gl');

return {
  json: {
    isValid: errors.length === 0,
    errors: errors,
    prenom,
    email,
    nom_commerce,
    ville,
    nb_avis,
    segment,
    lien_google,
    hasGoogleLink,
    timestamp: new Date().toISOString(),
    searchQuery: `${nom_commerce} ${ville}`
  }
};

// ═══════════════════════════════════════════
// EXTRACTION & STRUCTURATION DES DONNÉES
// ═══════════════════════════════════════════

const results = $input.first().json;
const formData = $('② Validation Données').first().json;

// Apify retourne un array — on prend le premier résultat
// Si recherche auto, on prend le plus pertinent
let allResults = Array.isArray(results) ? results : [results];

if (allResults.length === 0 || !allResults[0]) {
  return {
    json: {
      ficheFound: false,
      ...formData,
      errorReason: 'Aucun résultat Apify'
    }
  };
}

// Sélection du meilleur résultat (le premier pour scrape direct, 
// le plus pertinent pour recherche auto)
let place = allResults[0];

// Si recherche auto, essayer de matcher le nom
if (!formData.hasGoogleLink && allResults.length > 1) {
  const searchName = formData.nom_commerce.toLowerCase();
  const matched = allResults.find(r => 
    (r.title || r.name || '').toLowerCase().includes(searchName) ||
    searchName.includes((r.title || r.name || '').toLowerCase())
  );
  if (matched) place = matched;
}

// Extraction des avis
const reviews = (place.reviews || []).slice(0, 20).map(r => ({
  text: r.text || r.textTranslated || '',
  stars: r.stars || r.rating || 0,
  date: r.publishedAtDate || r.date || '',
  ownerResponse: r.responseFromOwnerText || null
}));

// Extraction des concurrents (autres résultats si recherche auto)
const competitors = allResults
  .filter(r => r !== place)
  .slice(0, 3)
  .map(r => ({
    name: r.title || r.name || 'Inconnu',
    rating: r.totalScore || r.rating || 0,
    reviewCount: r.reviewsCount || r.reviews?.length || 0,
    category: r.categoryName || r.category || ''
  }));

return {
  json: {
    ficheFound: true,
    ...formData,
    fiche: {
      name: place.title || place.name || formData.nom_commerce,
      address: place.address || place.street || '',
      phone: place.phone || '',
      website: place.website || place.url || '',
      category: place.categoryName || place.category || '',
      rating: place.totalScore || place.rating || 0,
      reviewCount: place.reviewsCount || reviews.length,
      url: place.url || place.link || formData.lien_google,
      imageUrl: place.imageUrl || '',
      openingHours: place.openingHours || []
    },
    reviews,
    competitors,
    reviewTextsForAI: reviews.map(r => `[${r.stars}★] ${r.text}`).join('\n')
  }
};

// ═══════════════════════════════════════════
// CONSTRUCTION DU PROMPT GEMINI
// ═══════════════════════════════════════════

const data = $input.first().json;

const systemPrompt = `Tu es un consultant expert en marketing local et e-réputation pour les commerces de proximité en France. 
Tu analyses les avis Google d'un commerce et produis un diagnostic structuré.

RÈGLES STRICTES :
- Réponds UNIQUEMENT en JSON valide, sans texte avant ni après
- Sois direct, concret, actionnable
- Adapte le ton au segment du commerce
- Les recommandations doivent être faisables par un commerçant non-tech
- Utilise le tutoiement professionnel`;

const userPrompt = `Analyse ce commerce et génère un diagnostic complet.

## INFORMATIONS DU COMMERCE
- Nom : ${data.fiche.name}
- Ville : ${data.ville}
- Catégorie : ${data.fiche.category}
- Note moyenne : ${data.fiche.rating}/5
- Nombre d'avis : ${data.fiche.reviewCount}
- Segment : ${data.segment} avis

## AVIS RÉCENTS (du plus récent au plus ancien)
${data.reviewTextsForAI}

## CONCURRENTS PROCHES
${data.competitors.map(c => `- ${c.name} : ${c.rating}/5 (${c.reviewCount} avis)`).join('\n') || 'Données concurrents non disponibles'}

## FORMAT DE RÉPONSE ATTENDU (JSON strict)
{
  "score_risque": <number 1-10, 10 = risque maximal>,
  "resume_situation": "<string, 2 phrases max résumant la situation>",
  "points_forts": [
    { "titre": "<string>", "detail": "<string, extrait d'avis ou observation>" },
    { "titre": "<string>", "detail": "<string>" },
    { "titre": "<string>", "detail": "<string>" }
  ],
  "faiblesses": [
    { "titre": "<string>", "detail": "<string>", "impact": "<string>" },
    { "titre": "<string>", "detail": "<string>", "impact": "<string>" }
  ],
  "potentiel_avis_30j": {
    "estimation": <number>,
    "methode": "<string, comment atteindre ce chiffre>"
  },
  "actions_prioritaires": [
    { "action": "<string>", "difficulte": "facile|moyen|avancé", "impact": "fort|moyen|faible", "delai": "<string>" },
    { "action": "<string>", "difficulte": "facile|moyen|avancé", "impact": "fort|moyen|faible", "delai": "<string>" },
    { "action": "<string>", "difficulte": "facile|moyen|avancé", "impact": "fort|moyen|faible", "delai": "<string>" }
  ],
  "recommandation_segment": "<string, paragraphe personnalisé selon le segment ${data.segment}>"
}`;

return {
  json: {
    ...data,
    geminiPayload: {
      contents: [
        {
          role: "user",
          parts: [{ text: userPrompt }]
        }
      ],
      systemInstruction: {
        parts: [{ text: systemPrompt }]
      },
      generationConfig: {
        temperature: 0.3,
        topP: 0.8,
        topK: 40,
        maxOutputTokens: 8192,
        responseMimeType: "application/json"
      }
    }
  }
};

// ═══════════════════════════════════════════
// PARSE DE LA RÉPONSE GEMINI (v3 — final)
// ═══════════════════════════════════════════

const geminiResponse = $input.first().json;
const previousData = $('⑧ Préparation Prompt Gemini').first().json;

// Extraction du texte — un seul part, pas de thinking
let rawText = '';
try {
  const parts = geminiResponse.candidates[0].content.parts;
  for (const part of parts) {
    if (part.text && !part.thought) {
      rawText = part.text;
    }
  }
  if (!rawText) {
    rawText = parts[parts.length - 1].text || '';
  }
} catch (e) {
  throw new Error('Structure Gemini inattendue : ' + JSON.stringify(geminiResponse).substring(0, 1000));
}

// Parse JSON
let analysis;
try {
  let cleaned = rawText.trim();
  cleaned = cleaned.replace(/^```json\s*/i, '');
  cleaned = cleaned.replace(/^```\s*/i, '');
  cleaned = cleaned.replace(/\s*```$/i, '');
  cleaned = cleaned.trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  throw new Error('JSON invalide : ' + rawText.substring(0, 500));
}

const { geminiPayload, reviewTextsForAI, ...cleanData } = previousData;

return {
  json: {
    ...cleanData,
    analysis
  }
};

// ═══════════════════════════════════════════
// GÉNÉRATION DU HTML DIAGNOSTIC
// ═══════════════════════════════════════════

const d = $input.first().json;
const a = d.analysis;
const f = d.fiche;

// Couleur du score de risque
function getScoreColor(score) {
  if (score <= 3) return '#22c55e';  // vert
  if (score <= 6) return '#f59e0b';  // orange
  return '#ef4444';                   // rouge
}

function getScoreLabel(score) {
  if (score <= 3) return 'Faible';
  if (score <= 6) return 'Modéré';
  return 'Élevé';
}

// Étoiles visuelles
function stars(rating) {
  const full = Math.floor(rating);
  const half = rating % 1 >= 0.5 ? 1 : 0;
  const empty = 5 - full - half;
  return '★'.repeat(full) + (half ? '½' : '') + '☆'.repeat(empty);
}

const scoreColor = getScoreColor(a.score_risque);
const scoreLabel = getScoreLabel(a.score_risque);
const scorePercent = (a.score_risque / 10) * 100;

// URL du Kit Express (à personnaliser)
