// ═══════════════════════════════════════════
// CONVERSION HTML → PDF VIA GOTENBERG
// Mode : Run Once for Each Item
// ═══════════════════════════════════════════

const item = $input.item.json;

const html = item.htmlDiagnostic;
const filename = item.pdfFilename;

// Buffer du HTML
const htmlBuffer = Buffer.from(html, 'utf-8');

// On prépare un fichier binaire pour n8n
const binaryHtml = await this.helpers.prepareBinaryData(
  htmlBuffer,
  'index.html',
  'text/html'
);

// Requête vers Gotenberg
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://gotenberg:3000/forms/chromium/convert/html',
  body: {
    marginTop: '0.4',
    marginBottom: '0.4',
    marginLeft: '0.4',
    marginRight: '0.4',
    paperWidth: '8.27',
    paperHeight: '11.69',
  },
  // On envoie le fichier HTML comme binaire
  // n8n gère automatiquement le multipart correct
  formData: {
    files: binaryHtml,
  },
  encoding: 'arraybuffer',
  returnFullResponse: false,
});

// Conversion en binaire PDF
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(response),
  filename,
  'application/pdf'
);

return {
  json: item,
  binary: {
    data: binaryData,
  },
};

const html = $json.htmlDiagnostic;

if (!html) {
  return [{
    json: {
      error: "htmlDiagnostic manquant",
      received: $json
    }
  }];
}

const b64 = Buffer.from(html).toString('base64');

return [{
  json: {},
  binary: {
    htmlFile: {
      data: b64,
      fileName: 'index.html',
      mimeType: 'text/html'
    }
  }
}];
